var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>도시관리국에서 범죄자들에게 통보한다. 이것은 마지막 경고다.</color>","JPN":"<color=#ffd34c>都市管理局より犯罪者たちに告ぐ。これは最後の警告だ。</color>","ENG":"<color=#ffd34c>City Management to all criminals. This is your last warning.</color>","TWN":"<color=#ffd34c>罪犯聽著，這是城市管理局最後一次警告。</color>"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>지금 무기를 버리고 투항하지 않으면, 전원 사살하겠다.</color>","JPN":"<color=#ffd34c>今すぐ武器を捨てて投降しなければ、全員射殺する。</color>","ENG":"<color=#ffd34c>Put down your weapons and surrender, or we will fire.</color>","TWN":"<color=#ffd34c>趕快棄械投降，否則將全面開火！</color>"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"……우릴 쫓는 추격대가 아직도 제법 많군.","JPN":"……我らを追う追撃隊がまだ結構いるな。","ENG":"...I see we still have company chasing after us.","TWN":"……沒想到有這麼多人在追趕我們。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"결계를 제거해서 도시에 괴물을 풀고, 관리국의 본체가 이 사태에 신경 쓰지 못할 시기를 노렸는데도 말이야.","JPN":"結界を取り除いて都市に化け物を放ち、管理局の本体がこの事態に気づけない時期を狙ったというのに。","ENG":"Even with all the distractions of letting loose monsters after removing the city's barrier, thus keeping the Administration occupied.","TWN":"原本解除結界把怪物釋放到城市裡，就是要讓管理局沒餘力可以注意到我們。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"걱정 마세요, 아버지. 제가 전부 죽이면 되니까요.","JPN":"心配いりません、お父様。私が全部殺せばいいだけのことです。","ENG":"Don't worry, father. I'll kill them all for you.","TWN":"父親別擔心，我把他們全都幹掉就好。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"아직 서두르지 마라.","JPN":"早まるな。","ENG":"No need to hurry.","TWN":"先別急。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"모처럼 이렇게 많은 피실험체가 모였는데, 그런 결과가 뻔한 실험은 아쉽지.","JPN":"せっかくここまでの数の被実験体が集まったのだ、結果が決まりきっている実験は物足りない。","ENG":"We are fortunate to have all these test subjects gathered today. A waste it would be to conduct experiments with obvious outcomes.","TWN":"難得有這麼多非實驗體聚在這裡，拿來做一翻兩瞪眼的實驗豈不是很可惜。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>무기를 버리지 않고 침묵한 채 계속해서 이동 중입니다.</color>","JPN":"<color=#ffd34c>武器を捨てずに沈黙を守って移動を続けています。</color>","ENG":"<color=#ffd34c>They are ignoring our orders and marching forward.</color>","TWN":"<color=#ffd34c>罪犯沒有棄械，而是保持沉默繼續移動。</color>"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>예상경로는 NAA-07…… 관리불가구역.</color>","JPN":"<color=#ffd34c>予想経路はNAA-07……管理不可エリア。</color>","ENG":"<color=#ffd34c>Estimated destination is NAA-07... The Unadministerable Zone.</color>","TWN":"<color=#ffd34c>預計路徑是NAA-07…… 拒絕管理區域。</color>"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>타깃에겐 투항 의지가 없는 것으로 판단. 무력진압을 위해 대기 중인 병력을 투입합니다.</color>","JPN":"<color=#ffd34c>ターゲットには投降する意志がないものと判断。武力鎮圧のため、待機中の兵力を投入します。</color>","ENG":"<color=#ffd34c>Target shows no signs of forfeit. Deploying troops to arrest by force.</color>","TWN":"<color=#ffd34c>判斷目標沒有棄械投降的意願，投入全部兵力進行武力鎮壓。</color>"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOLDIER_NPC_UNION_NULL","text":{"KOREA":"유다님, 이동 결계 시스템의 준비절차를 마쳤습니다.","JPN":"ユダ様、移動結界システムの用意が完了いたしました。","ENG":"Preparations for the mobile barrier system are complete, sir.","TWN":"報告，移動結界系統已經準備完畢。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"다들 지금까지 잘해주었다. 이제 대업을 이룩하기까지 머지 않았다.","JPN":"皆の者、ここまでよくやってくれた。大業を成すまであとわずかだ。","ENG":"Well done, everyone. It is only a matter of time before we achieve greatness.","TWN":"大家這段時間都很努力，現在距離完成霸業只剩幾步之遙。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그대들의 희생은 조국이 기억할 것이다.","JPN":"諸君の犠牲は祖国の歴史に残るだろう。","ENG":"The motherland will remember your sacrifice.","TWN":"國家會紀念你們的犧牲的。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"북방합의체를 위해! 그 어떤 희생도 마다치 않으리!","JPN":"北方合意体のために！　どんな犠牲もいとわない！","ENG":"For the Northern Union! Life for the motherland!","TWN":"為了北方和議會！不惜任何犧牲！"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>무슨 소리지? 벌써 교전이 일어났나?</color>","JPN":"<color=#ffd34c>何の音だ？　もう交戦が始まったのか？</color>","ENG":"<color=#ffd34c>Do you hear that? Is there a battle going on?</color>","TWN":"<color=#ffd34c>什麼聲音？開戰了嗎？</color>"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};